function checkIfDerogatory(
  accountData: Record<string, Record<string, string>>,
  paymentHistory?: Record<'transunion' | 'experian' | 'equifax', PaymentHistorySummary>
): boolean {
  for (const bureau of ['transunion', 'experian', 'equifax'] as const) {
