    // Check if this is the inquiry table by looking at headers
    $table.find('tr').first().find('th, td').each((_, cell) => {
      const text = $(cell).text().toLowerCase();
      if (text.includes('business') || text.includes('inquiry')) {
        isInquiryTable = true;
      }
